# spaCy-based NER for entity detection
# Install: pip install spacy && python -m spacy download en_core_web_sm

import spacy

nlp = spacy.load("en_core_web_sm")

ENTITY_TO_LABEL = {
    "PERSON":   "INTERNAL",    # names alone are typically INTERNAL
    "ORG":      "INTERNAL",
    "GPE":      "PUBLIC",      # countries/cities are public
    "MONEY":    "CONFIDENTIAL",
    "DATE":     "PUBLIC",
    "CARDINAL": "PUBLIC",
}

# Combinations that escalate sensitivity
COMBINATION_RULES = [
    ({"PERSON", "MONEY"}, "CONFIDENTIAL"),      # name + money amount
    ({"PERSON", "ORG", "DATE"}, "CONFIDENTIAL"), # person + org + date (HR context)
]

def classify_by_ner(text: str) -> tuple[str, list[str]]:
    doc = nlp(text)
    found_types = {ent.label_ for ent in doc.ents}
    max_label = "PUBLIC"
    labels_order = ["PUBLIC", "INTERNAL", "CONFIDENTIAL", "RESTRICTED"]

    # Single entity type rules
    for ent_type in found_types:
        assigned = ENTITY_TO_LABEL.get(ent_type, "PUBLIC")
        if labels_order.index(assigned) > labels_order.index(max_label):
            max_label = assigned

    # Combination escalation rules
    for required_types, combo_label in COMBINATION_RULES:
        if required_types.issubset(found_types):
            if labels_order.index(combo_label) > labels_order.index(max_label):
                max_label = combo_label

    return max_label, list(found_types)

